+#![no_main]
+
+use libfuzzer_sys::fuzz_target;
+
+const MAX_OP_CHAIN_BYTES: usize = 64 * 1024;
+
+fuzz_target!(|data: &[u8]| {
+    if data.len() > MAX_OP_CHAIN_BYTES {
+        return;
+    }
+
+    let _ = fp_conformance::fuzz_dataframe_op_chain_bytes(data);
+});
